#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json
import sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` but allow `pnpm test:ci` and similar variants
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd and cmd.strip() != "pnpm test --help":
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""PostToolUse hook: after Edit, check if new recursion lacks depth guards."""
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    new_string = inp.get("new_string", "")

    # Detect recursive function definitions
    # Pattern: function calls itself by name
    func_defs = re.findall(r'^\s*def\s+(\w+)\s*\(', new_string, re.MULTILINE)

    for func_name in func_defs:
        # Check if function body contains self-call
        if re.search(rf'\b{func_name}\s*\(', new_string):
            # Self-recursive; check for depth guards
            has_depth_param = re.search(rf'def\s+{func_name}\s*\([^)]*\bdepth\b', new_string)
            has_max_depth = re.search(r'\bmax_depth\b', new_string)
            has_sys_setrecursionlimit = re.search(r'sys\.setrecursionlimit', new_string)
            has_depth_check = re.search(r'if.*depth\s*[><=]', new_string)

            if not (has_depth_param or has_max_depth or has_sys_setrecursionlimit or has_depth_check):
                print(
                    f"REQUIRED FOLLOW-UP: Function `{func_name}` is recursive but lacks depth guards. "
                    f"Add a `depth` or `max_depth` parameter with a check (e.g., `if depth > 1000: raise RecursionError`) "
                    f"OR convert to an iterative approach using a worklist. Do not stop until this is fixed.",
                    file=sys.stderr
                )
                return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing Python files, run ruff check and surface violations."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    if not os.path.isfile(file_path):
        return 0

    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.getenv("CLAUDE_PROJECT_DIR", os.getcwd())
        )

        if result.returncode != 0 and result.stdout.strip():
            print(f"REQUIRED FOLLOW-UP: ruff check found violations in {file_path}:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            print("Fix each violation, then proceed. Do not stop until all violations are resolved.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    old_string = inp.get("old_string", "")
    new_string = inp.get("new_string", "")

    # Check if this is a TypeScript file
    if not (file_path.endswith(".ts") or file_path.endswith(".tsx")):
        return 0

    # Check if the old_string contains 'export' keyword
    if "export" not in old_string:
        return 0

    # Look for exported const/let/var declarations with string values
    # Pattern: export (const|let|var) IDENTIFIER = 'value' or "value"
    export_value_pattern = r'\bexport\s+(?:const|let|var)\s+(\w+)\s*=\s*["\']([^"\']+)["\']'

    old_exports = {}  # identifier -> value
    new_exports = {}

    for match in re.finditer(export_value_pattern, old_string):
        identifier, value = match.groups()
        old_exports[identifier] = value

    for match in re.finditer(export_value_pattern, new_string):
        identifier, value = match.groups()
        new_exports[identifier] = value

    # Check if any export values changed
    changed_exports = []
    for identifier in old_exports:
        if identifier in new_exports and old_exports[identifier] != new_exports[identifier]:
            changed_exports.append((identifier, old_exports[identifier], new_exports[identifier]))

    # Also check for renamed/removed identifiers
    removed_identifiers = set(old_exports.keys()) - set(new_exports.keys())
    added_identifiers = set(new_exports.keys()) - set(old_exports.keys())

    if not (changed_exports or removed_identifiers):
        return 0

    # REQUIRED FOLLOW-UP
    print("REQUIRED FOLLOW-UP: Exported identifier or value changed.", file=sys.stderr)
    print(f"File: {file_path}", file=sys.stderr)

    if changed_exports:
        for identifier, old_val, new_val in changed_exports:
            print(f"  {identifier}: '{old_val}' → '{new_val}'", file=sys.stderr)

    if removed_identifiers:
        print(f"  Removed: {', '.join(sorted(removed_identifiers))}", file=sys.stderr)

    print("", file=sys.stderr)
    print("Do not stop until you:", file=sys.stderr)
    print("1. Grep for all references to the old identifier(s) or hardcoded old value(s)", file=sys.stderr)
    print("2. Show the user every file that imports or hardcodes the old value", file=sys.stderr)
    print("3. Update each reference to use the new name/value", file=sys.stderr)

    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block git commit with verbose paragraph-style messages.
Team convention: short imperative subject line."""
import json, re, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")
    if "git commit" not in cmd or "-m" not in cmd:
        return 0

    # Extract message from HEREDOC or simple quoted format
    msg = ""
    heredoc = re.search(r'-m\s+"?\$\(cat\s+<<["\']?EOF["\']?\s*(.*?)\s*EOF', cmd, re.DOTALL)
    if heredoc:
        msg = heredoc.group(1).strip()
    else:
        simple = re.search(r'-m\s+["\']([^"\']+ )["\']', cmd)
        if simple:
            msg = simple.group(1).strip()

    if not msg:
        return 0

    # Strip Co-Authored-By line if present (allowed)
    msg_clean = re.sub(r'\n\s*Co-Authored-By:.*$', '', msg, flags=re.IGNORECASE)

    # Count periods in entire message (paragraph indicator)
    period_count = msg_clean.count('.')

    # Short imperative messages have 0-1 periods; paragraphs have 2+
    if period_count >= 3:
        print('Commit message is a paragraph. Team convention: short imperative subject.\nExample: "Refactor auth: extract token validation"', file=sys.stderr)
        return 2

    # Check first line length
    first = msg_clean.split('\n')[0].strip()
    if len(first) > 100:
        print('Commit message subject line is too long. Team convention: short imperative subject.\nExample: "Refactor auth: extract token validation"', file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

